import{_ as a,o as e,c as o,aj as r}from"./chunks/framework.DNJ2HNkG.js";const p=JSON.parse('{"title":"Ubuntu循环登录问题","description":"","frontmatter":{"title":"Ubuntu循环登录问题","date":"2016-06-22T22:37:41.000Z","category":"Linux","tags":["Linux","Ubuntu"]},"headers":[],"relativePath":"posts/Ubuntu循环登录问题.md","filePath":"posts/Ubuntu循环登录问题.md","lastUpdated":1783047625000}'),i={name:"posts/Ubuntu循环登录问题.md"};function n(s,t,d,l,_,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<p>总结出几种情况：</p><h2 id="_1、lightdm登陆后-直接回到登陆界面" tabindex="-1">1、lightdm登陆后，直接回到登陆界面 <a class="header-anchor" href="#_1、lightdm登陆后-直接回到登陆界面" aria-label="Permalink to &quot;1、lightdm登陆后，直接回到登陆界面&quot;">​</a></h2><p>这种一般是 .Xauthority属主问题，通常都是变成了root 改成当前用户即可</p><h2 id="_2、lightdm登陆后-出现终端字符界面然迅速回到登陆界面" tabindex="-1">2、lightdm登陆后，出现终端字符界面然迅速回到登陆界面 <a class="header-anchor" href="#_2、lightdm登陆后-出现终端字符界面然迅速回到登陆界面" aria-label="Permalink to &quot;2、lightdm登陆后，出现终端字符界面然迅速回到登陆界面&quot;">​</a></h2><p>这种情况一般是环境变量问题，检查/etc/profile和/etc/enviroment，以及当前用户目录的下.bashrc和.bash_profile</p><h2 id="_3、lightdm登陆后-进入桌面-闪烁几次后回到登陆界面" tabindex="-1">3、lightdm登陆后，进入桌面，闪烁几次后回到登陆界面 <a class="header-anchor" href="#_3、lightdm登陆后-进入桌面-闪烁几次后回到登陆界面" aria-label="Permalink to &quot;3、lightdm登陆后，进入桌面，闪烁几次后回到登陆界面&quot;">​</a></h2><p>这种问题很罕见，在.xsession-errors也找不到异常，权限什么也都OK</p><p>继续分析，guest用户可以登陆，创建新的用户也能登陆，最后发现是dconf数据库问题</p><p>也就是用户目录下 .config/dconf/user文件问题，删除这个文件即可，虽然桌面图标这些配置就得重新配置了。</p>',9)])])}const c=a(i,[["render",n]]);export{p as __pageData,c as default};
